<?php require APP_ROOT.'/app/views/layouts/header.php';?><h3>Candidate Matching — Requirement #<?=$requirement['id']?></h3><div class="card mb-3"><div class="card-body"><b><?=htmlspecialchars($requirement['manpower_type'])?></b> | <?=htmlspecialchars($requirement['location'])?> | Required: <?=$requirement['number_of_staff']?></div></div><form method="post" action="<?=BASE_URL?>/matching/shortlist"><input type="hidden" name="requirement_id" value="<?=$requirement['id']?>"><div class="card"><table class="table mb-0"><tr><th>Select</th><th>Name</th><th>Job Type</th><th>Skills</th><th>Experience</th><th>Location</th></tr><?php foreach($candidates as $c):?><tr><td><input type="checkbox" name="candidate_ids[]" value="<?=$c['id']?>"></td><td><?=$c['name']?></td><td><?=$c['job_type']?></td><td><?=$c['skills']?></td><td><?=$c['experience']?></td><td><?=$c['preferred_location']?></td></tr><?php endforeach;?></table></div><button class="btn btn-success mt-3">Shortlist Selected</button></form><?php if($matched):?><div class="card mt-4"><table class="table mb-0"><tr><th>Name</th><th>Status</th><th>Action</th></tr><?php foreach($matched as $m):?><tr><td><?=$m['name']?></td><td><?=$m['status']?></td><td><a class="btn btn-sm btn-primary" href="<?=BASE_URL?>/matching/status?id=<?=$requirement['id']?>&match_id=<?=$m['id']?>&status=sent">Send to Client</a> <a class="btn btn-sm btn-success" href="<?=BASE_URL?>/matching/status?id=<?=$requirement['id']?>&match_id=<?=$m['id']?>&status=selected">Selected</a></td></tr><?php endforeach;?></table></div><?php endif;require APP_ROOT.'/app/views/layouts/footer.php';?>